bootstrap-table 行编辑html 代码&lt;div class="container">
	&lt;div class="asset_title">
		&lt;div class="asset_left">&lt;span>考试管理信息&lt;/span>&lt;/div>
		&lt;div class="asset_right">
			&lt;ul>
				&lt;li class="w80" onclick="insertRow()">添加试题&lt;/li>
			&lt;/ul>
		&lt;/div>
	&lt;/div>
	&lt;div id="myTabContent" class="tab-content tab-second ">
		&lt;table id="tableOne" class="text-nowrap">&lt;/table>
	&lt;/div>
&lt;/div>

js 代码&lt;script type="text/javascript">
$(function()&#123;
	initTable();
	//保存
	$("#saveExamPaper").bind("click",function()&#123;
		var rows = $('#tableOne').bootstrapTable('getData',false);
		for(i=0;i&lt;rows.length;i++)&#123;
       	 	if(rows[i].qubankId == null)&#123;
       	 		dialog("请先选择题库！");
           	 	return;
       	 	&#125;
       	 if(rows[i].radioCount &lt;= 0 || rows[i].multiCount &lt;= 0 || rows[i].judgeCount &lt;= 0 || rows[i].saqCount &lt;= 0)&#123;
    	 		dialog("题目数量不能为零！");
        	 	return;
    	 	&#125;
		&#125;
		$("#form").ajaxSubmit(&#123;
			type: "POST",//方法类型
	        dataType: 'json',//预期服务器返回的数据类型
	        url: "&lt;%=basePath%>examPaperWeb/addOrEdit.so",
	        async: true,
	        success: function (result) &#123;
           	 	if(result.success)&#123;//保存成功跳转到列表页面
               	 	$.each(rows, function(index, e)&#123;
                   	 	e.paperId = result.data;//为考试题库赋值试卷id
                   	 	&#125;);
	           	 	$.ajax(&#123;
	        			type: "POST",//方法类型
	        	        dataType: 'json',//预期服务器返回的数据类型
	        	        url: "&lt;%=basePath%>examRepoWeb/addOrEdit.so",
	        	        data: &#123;lists: rows&#125;,
	        	        async: true,
	        	        success: function (result) &#123;
	                   	 	if(result.success)&#123;//保存成功跳转到列表页面

	                       	 	url = "&lt;%=basePath%>examPaperWeb/listPage.so";
	                   			dialogUrl(result.message, url);
	            			&#125;else&#123;
	            				dialog(result.message);
	            			&#125;
	                    &#125;,
	                    error : function() &#123;
	                    	dialog("系统异常，请联系管理员！");
	                    &#125;
	        	    &#125;);
    			&#125;else&#123;
    				dialog(result.message);
    			&#125;
            &#125;,
            error : function() &#123;
            	dialog("系统异常，请联系管理员！");
            &#125;
	    &#125;);
		//删除已关联的题库关联关系
		if(rowList &amp;&amp; rowList.length>0)&#123;
			$.ajax(&#123;
				type: "POST",//方法类型
		        dataType: 'json',//预期服务器返回的数据类型
		        url: "&lt;%=basePath%>examRepoWeb/delByIds.so",
		        data: "rowList="+rowList,
		        async: true,
		        success: function (result) &#123;
	           	 	if(!result.success)&#123;//保存成功跳转到列表页面
	    				dialog(result.message);
	    			&#125;
	            &#125;,
	            error : function() &#123;
	            	dialog("系统异常，请联系管理员！");
	            &#125;
		    &#125;);
		&#125;
	&#125;);

	//取消
	$("#return").click(function()&#123;
		window.location.href="&lt;%=basePath%>examPaperWeb/listPage.so";

	&#125;);
&#125;);

//选择题库弹窗
function choiceQU(index, qubankId, id)&#123;
	var obj = &#123;&#125;;
	obj.choiceNum = qubankId;
	var url = "&lt;%=basePath%>examPaperWeb/quBankPage.so";
	var win = showModalDialog(url,obj,"scroll:yes;status:no;dialogWidth:800px;dialogHeight:450px");

	if (win != null) &#123;//重新选择题库，题目设置清零
		$("#tableOne").bootstrapTable('updateRow', &#123;index: index, replace:true, row:&#123;
			id: id,
			qubankId: win[0],
			qubankTitle: win[1],
          	radioCount: 0,
          	radioScore: 0,
          	multiCount: 0,
          	multiScore: 0,
          	judgeCount: 0,
          	judgeScore: 0,
          	saqCount: 0,
          	saqScore: 0
			&#125;&#125;);
	&#125;
&#125;

//获取查询参数
function queryParams(params) &#123;
	var quarP=&#123;
	        pageSize : params.pageSize, // 每页显示数量
	        pageNo : params.pageNumber, // 当前页
	        paperId : $('#id').val()
	    &#125;
    return quarP;
&#125;

//初始话表格
function  initTable()&#123;
	//先销毁表格
	$('#tableOne').bootstrapTable('destroy');
	//表格数据
	$('#tableOne').bootstrapTable(&#123;
	        method: 'post',
	        contentType:'application/x-www-form-urlencoded; charset=UTF-8',
	        url: '&lt;%=basePath%>examRepoWeb/listByPaperId.so',
	        striped: true,//使表格带有条纹
	        pagination: true,//在表格底部显示分页工具栏
	        sortable:true,
	        sortOrder: "asc",
	        clickEdit: true,
	        pageSize: 5,
	        pageList: customPageList,
	        paginationShowPageGo: true,		//显示跳转页码
	        sidePagination: "server",//表格分页的位置
	        search: false,          //是否显示表格搜索，此搜索是客户端搜索，不会进服务端
	        showColumns: false,     //是否显示所有的列
	        minimunCountColumns: 2,
	        showColumns: false, //显示隐藏列  
	        showRefresh: false,  //显示刷新按钮
	        silent : true, 	     // 必须设置刷新事件
	        singleSelect: false,//复选框只能选择一条记录
	        //clickToSelect: true,//点击行即可选中单选/复选框
	        queryParams: queryParams, //参数
	        queryParamsType: "", //参数格式,发送标准的RESTFul类型的参数请求
	        columns:[
	                 &#123;title: '序号',field: 'index',align: 'center',width:'50px',formatter:function(value, row, index)&#123;
		                	var pageSize = $('#tableOne').bootstrapTable('getOptions').pageSize;//通过表的#id 可以得到每页多少条
	                        var pageNumber = $('#tableOne').bootstrapTable('getOptions').pageNumber;//通过表的#id 可以得到当前第几页
	                        return pageSize * (pageNumber - 1) + index + 1;//返回每条的序号： 每页条数 * （当前页 - 1 ）+ 序号
							//return index+1;
		             &#125;&#125;,
		             //&#123;radio: true,valign:"middle",align:"center",formatter: function (value, row, index)&#123;
	    		     //&#125;&#125;,//单选框
		             //&#123;field: 'stat',checkbox: true&#125;, //复选框
		             &#123;field: 'id',title: "考试题库id",valign:"middle",align:"center",visible:false&#125;,
		             &#123;field: 'qubankId',title: "题库id",valign:"middle",align:"center",visible:false&#125;,
		             &#123;field: 'qubankTitle',title: "题库",valign:"middle",align:"center",isTip:false,formatter:function(value,row,index)&#123;
		            	 return '&lt;div style="cursor:pointer;" onclick="choiceQU('+index+','+row.qubankId+','+row.id+')">'+value+'&lt;/div>';
		             &#125;&#125;,
		             &#123;field: 'radioCount',title: "单选题数量",valign:"middle",align:"center",isTip:false,formatter:function(value)&#123;
			             return '&lt;div contentEditable="true">' + value + '&lt;/div>'&#125;&#125;,
		             &#123;field: 'radioScore',title: "单选题分数",valign:"middle",align:"center",isTip:false,formatter:function(value)&#123;
				         return '&lt;div contentEditable="true">' + value + '&lt;/div>'&#125;&#125;,
		             &#123;field: 'multiCount',title: "多选题数量",valign:"middle",align:"center",isTip:false,formatter:function(value)&#123;
					     return '&lt;div contentEditable="true">' + value + '&lt;/div>'&#125;&#125;,
		             &#123;field: 'multiScore',title: "多选题分数",valign:"middle",align:"center",isTip:false,formatter:function(value)&#123;
						 return '&lt;div contentEditable="true">' + value + '&lt;/div>'&#125;&#125;,
		             &#123;field: 'judgeCount',title: "判断题数量",valign:"middle",align:"center",isTip:false,formatter:function(value)&#123;
						return '&lt;div contentEditable="true">' + value + '&lt;/div>'&#125;&#125;,
		             &#123;field: 'judgeScore',title: "判断题分数",valign:"middle",align:"center",isTip:false,formatter:function(value)&#123;
						return '&lt;div contentEditable="true">' + value + '&lt;/div>'&#125;&#125;,
		             &#123;field: 'saqCount',title: "简答题数量",valign:"middle",align:"center",isTip:false,formatter:function(value)&#123;
						return '&lt;div contentEditable="true">' + value + '&lt;/div>'&#125;&#125;,
		             &#123;field: 'saqScore',title: "简答题分数",valign:"middle",align:"center",isTip:false,formatter:function(value)&#123;
						return '&lt;div contentEditable="true">' + value + '&lt;/div>'&#125;&#125;,
		             &#123;field: 'index',title: "操作",valign:"middle",align:"center",isTip:false,formatter: function (value, row, index)&#123;
	                    	 var url = '&lt;a href="javascript:void(0)" style="color:blue" onclick="removeRow('+value+','+row.id+')">&lt;img src="skin/meteringTS/custom/images/deletes.png" />&lt;/a>';
	                         return url;  
	    		         &#125;&#125;
		    	],
	    	onClickCell: function(field, value, row, $element)&#123;
		    	if(field=='qubankTitle' || field=='index')
			    	return;
		    	if(!row.qubankId || row.qubankId == null || row.qubankId == '')&#123;
		    		dialog("请先选择题库！");
			    	return;
		    	&#125;
			    $element.children().blur(function()&#123;
				    var index = $element.parent().data('index');
				    var tdValue = $element.children().html();
				    var reg = new RegExp(/^\+?[1-9][0-9]*$/);
				    if (!reg.test(tdValue)) &#123;
				    	tdValue = value;
				    &#125;
					//校验题库题目数量是否满足所填试题数量
					if(field=='radioCount' || field=='multiCount' || field=='judgeCount' || field=='saqCount')&#123;
						$.ajax(&#123;
							type: "POST",//方法类型
					        dataType: 'json',//预期服务器返回的数据类型
					        url: "&lt;%=basePath%>examQuesWeb/list.so",
					        data: &#123;qubankId: row.qubankId&#125;,
					        async: true,
					        success: function (result) &#123;
						        console.log(result);
				           	 	if(result.total &lt; tdValue)&#123;//保存成功跳转到列表页面
				    				dialog("题库题目数量不足！");
				    				$("#tableOne").bootstrapTable('updateCell', &#123;index: index, field: field,value: value&#125;);
				    			&#125;
				            &#125;,
				            error : function() &#123;
				            	dialog("系统异常，请联系管理员！");
				            &#125;
			    		&#125;);
					&#125;
				    $("#tableOne").bootstrapTable('updateCell', &#123;index: index, field: field,value: tdValue&#125;);
				    calcTotal();
				    &#125;);
		   	&#125;
	    &#125;);
&#125;

function insertRow()&#123;
	//获取对象
	var obj=$('#tableOne');
	var count = obj.bootstrapTable('getData').length;
	//插入数据到末尾
	obj.bootstrapTable('insertRow', &#123;
		index: count,
		row: &#123;
			index: count,
			id: null,
			qubankId: null,
			qubankTitle: '请选择',
          	radioCount: 0,
          	radioScore: 0,
          	multiCount: 0,
          	multiScore: 0,
          	judgeCount: 0,
          	judgeScore: 0,
          	saqCount: 0,
          	saqScore: 0
		&#125;
	  &#125;);
	$(".pagination-info").html("总记录"+(count+1)+" 条");
&#125;

//删除一行
var rowList = [];
function removeRow(index, id)&#123;
	var count = $("#tableOne").bootstrapTable('getData').length;
	if(id)&#123;
		rowList.push(id);
		//删除一行数据
		$("#tableOne").bootstrapTable('remove', &#123;field: 'id',values: [parseInt(id)] &#125;);
	&#125;else&#123;
		//删除一行数据
		$("#tableOne").bootstrapTable('remove', &#123;field: 'index',values: [parseInt(index)] &#125;);
	&#125;
	$(".pagination-info").html("总记录"+(count-1&lt;0?0:count-1)+" 条");
	calcTotal();//重新计算总分
&#125;
&lt;/script>

html代码&lt;!DOCTYPE html>
&lt;meta http-equiv="X-UA-Compatible" content="IE=edge,Chrome=1" />&lt;!-- 兼容ie -->
&lt;html>
&lt;head>
&lt;base href="&lt;%=basePath%>">
&lt;title>&lt;/title>
&lt;script type="text/javascript">
	var basePath = "$&#123;basePath&#125;";
	var staticBasePath = "$&#123;staticBasePath&#125;";;
&lt;/script>
&lt;!-- jquery 文件-->
&lt;script type="text/javascript" src="skin/meteringTS/jquery/jquery-1.9.1.js" >&lt;/script>
&lt;script type="text/javascript" src="skin/meteringTS/jquery/jquery.form.js" >&lt;/script>
&lt;!-- bootstrap 文件 -->
&lt;link rel="stylesheet" href="skin/meteringTS/bootstrap/css/bootstrap.css">
&lt;script src="skin/meteringTS/bootstrap/js/bootstrap.min.js">&lt;/script>
&lt;link rel="stylesheet" href="skin/ztree/css/zTreeStyle/zTreeStyle.css" type="text/css">
&lt;script type="text/javascript" src="skin/ztree/js/jquery.ztree.core.js">&lt;/script>
&lt;script type="text/javascript" src="skin/ztree/js/jquery.ztree.excheck.js">&lt;/script>
&lt;script type="text/javascript" src="skin/ztree/js/jquery.ztree.exedit.js">&lt;/script>
&lt;script type="text/javascript" src="skin/ztree/js/jquery.ztree.exhide.min.js">&lt;/script>
&lt;/head>
&lt;body>
&lt;style type="text/css">
.table &#123;
        table-layout: fixed !important;
    &#125;
.table tbody tr td&#123;
    overflow: hidden;
    text-overflow:ellipsis;
    white-space: nowrap;
&#125;
.nav-tabs>LI.active>A &#123;
	color: #fff !important;
	background: #75BEAD !important
&#125;

.nav-tabs>LI>A &#123;
	color: #75B0A6 !important
&#125;

.nav-tabs>LI &#123;
	border-right: 1px solid #8ED7D2
&#125;

.nav-tabs>LI>A &#123;
	margin-right: 0px
&#125;

.nav-tabs &#123;
	border-bottom: 1px solid #8ED7D2 !important
&#125;

.nav>LI>A &#123;
	padding: 6px 12px
&#125;

.tab-pane &#123;
	height: 590px
&#125;

.btn &#123;
	color: #64B9B4;
	border-color: #54B2AC;
&#125;

/* 自动补全数据多时显示下拉框 */
.ui-autocomplete &#123;
	max-height: 200px;
	overflow-y: auto; /* 防止水平滚动条 */
	overflow-x: hidden;
&#125;

/* IE 6 不支持 max-height,我们使用 height 代替，但是这会强制菜单总是显示为那个高度 */
.ui-autocomplete &#123;
	height: 200px;
&#125;

.dist_statis &#123;
	border: none;
	min-width: 500px;
&#125;

.search &#123;
	padding-bottom: 0px;
	min-width: 500px;
&#125;

.fault_btn &#123;
	margin-top: 10px
&#125;

.statis_top ul &#123;
	padding: 0;
	padding-left: 1%
&#125;

.statis_top ul li &#123;
	cursor: pointer
&#125;

.asset_right ul &#123;
	margin-top: 2px
&#125;

.asset_right ul li &#123;
	float: left;
	list-style: none;
	margin-right: 15px;
	cursor: pointer;
	display: inline-block;
	line-height: 24px;
	text-align: center;
	color: #54B2AC
&#125;

.asset_title &#123;
	min-width: 500px;
&#125;

.w80 &#123;
	width: 80px;
	height: 24px;
	background: url(skin/meteringTS/custom/images/btn-bg-80.png)
&#125;

.w120 &#123;
	width: 120px;
	height: 24px;
	background: url(skin/meteringTS/custom/images/btn-bg-120.png)
&#125;

.w80:hover &#123;
	background: url(skin/meteringTS/custom/images/btn-bg-80-on.png)
&#125;

.w120:hover &#123;
	background: url(skin/meteringTS/custom/images/btn-bg-120-on.png)
&#125;

/* 弹出框样式修改 */
.ui-dialog-buttons,.ui-widget-content &#123;
&#125;

.ui-dialog-content &#123;
	border: none !important
&#125;

.ui-dialog-buttons .ui-dialog-content &#123;
&#125;

.ui-dialog-buttonset button &#123;
	border-color: #E3F3F2 !important;
	background-color: #E3F3F2 !important;
	outline: none !important;
&#125;

.onLeft &#123;
	width: 25%;
	height:90%;
	float:left;
	margin: 10px;
	overflow: hidden;
    overflow-y: auto;
	background-color:#F6FCFC;
	border:1px solid #6EC5B9;
&#125;

div.onLeft &#123;
	position: fixed;
	top: 0px;
&#125;

div.inquiry &#123;
    position: relative;
    left: 40px;
    margin: 10px;
    width: 200px;
&#125;

.table > TBODY > TR > TD &#123;
    padding: 4px 8px;
&#125;

div#rMenu &#123;
	position:absolute;
	visibility:hidden;
	top:0;
	text-align: center;
	padding: 2px;
	background:#DFDFDF;
&#125;

div#rMenu ul li&#123;
	margin: 1px 0;
	padding: 0 5px;
	cursor: pointer;
	list-style: none outside none;
	background-color: #DFDFDF;
&#125;

div#rMenu ul&#123;
	padding: 0px;
&#125;

.ztree * &#123;
	font-size: 14px;
&#125;

.ztree li a input.rename &#123;
	height:22px; 
	width:100%; 
	font-size: 14px;
&#125;
 html, body&#123;
	width: 100%;
 	height: 100%;
&#125;

.wrap &#123;
    height: 100%;
    position: relative;
    padding-top: 0px;
    padding-bottom: 10px;
    box-sizing: border-box;
&#125;
.right &#123;
    height: 100%;
    overflow: hidden;
    overflow-y: auto;
&#125;
&lt;/style>

&lt;div class="container wrap">
	&lt;div class="tab-content onLeft ">
		&lt;label for="key" class="col-sm-3 control-label" style="top:25px">搜索:&lt;/label>
		&lt;div class="inquiry">
			&lt;input type="text" id="key" value="" class="" />
			&lt;img src="./skin/meteringTS/custom/images/u975.png"/>
		&lt;/div>
		&lt;ul id="treeDemo" class="ztree">&lt;/ul>
		&lt;div id="rMenu">
			&lt;ul>
			&lt;li id="m_add" onclick="addTreeNode();">添加&lt;/li>
			&lt;li id="m_mov_up" onclick="moveNode(1);">上移&lt;/li>
			&lt;li id="m_mov_down" onclick="moveNode(0);">下移&lt;/li>
			&lt;li id="m_del" onclick="removeTreeNode();">删除&lt;/li>
			&lt;li id="m_rename" onclick="renameEditOpen();">重命名&lt;/li>
			&lt;/ul>
		&lt;/div>
	&lt;/div>
&lt;!-- 子页面 -->
	&lt;div class="right" style="border:1px solid #6EC5B9;">
		&lt;iframe id="iframeShow" frameborder="0" style="display: block;" width="100%" height='90%'>&lt;/iframe>
	&lt;/div>
&lt;/div>

&lt;!-- 模态弹框 -->
&lt;div id="op_div" style="display:none;">
	&lt;iframe id='op_iframe' frameborder='0' scrolling='auto' width='100%' height='100%'>&lt;/iframe>
&lt;/div>
&lt;!-- end container -->
&lt;/body>
&lt;/html>

js代码&lt;script type="text/javascript">
$(function()&#123;
	//初始化岗位树
	initTree();
	iframeShow("");
	//树型图搜索框事件绑定
	var key = $("#key");
	key.bind("propertychange", searchNode)
	.bind("input", searchNode);
&#125;)

//选中单选框并展示该项详细数据
function iframeShow(jobId)&#123;
	$("#iframeShow").attr("src","&lt;%=basePath%>relaJobStandardWeb/listPage.so?jobId=" + jobId);
&#125;


//ztree 设置
var setting = &#123;
        view: &#123;
            showIcon: false,
			dblClickExpand: false
        &#125;,
        data: &#123;
            simpleData: &#123;
                enable: true,
                idKey: "id", 
                pIdKey: "pid",
                rootPId: 0
            &#125;
        &#125;,
		callback: &#123;
			onClick: onClick,
			onRightClick: OnRightClick,
			onRename: onRename
		&#125;,
		view: &#123;
			fontCss: getFontCss,
			showIcon: false
		&#125;
		,edit: &#123;
			enable: true,
			showRenameBtn: false,
			showRemoveBtn: false,
			editNameSelectAll: true,
			drag: &#123;
				isCopy: false,
				isMove: false
			&#125;
		&#125;
    &#125;;

//字体样式
function getFontCss(treeId, treeNode) &#123;
	return (!!treeNode.highlight) ? &#123;color:"#A60000", "font-weight":"bold", "font-size":"18px"&#125; : &#123;color:"#333", "font-weight":"normal", "font-size":"18px"&#125;;
&#125;

function initTree()&#123;
	 $.ajax(&#123;
			url: '&lt;%=basePath%>jobIdentificationWeb/queryList.so',
			type:"POST", 
			async:false/*是否异步*/,
			data:&#123;&#125;,
			dataType: "json"
		&#125;).done(function(data)&#123;
			if(data)&#123;
				$.fn.zTree.init($("#treeDemo"), setting, data);
				var zTree = $.fn.zTree.getZTreeObj("treeDemo");
				zTree.expandAll(true);
			&#125;
		&#125;).fail(function(data)&#123;
			dialog("列表获取失败!");
	&#125;);
&#125;

//右键菜单
function OnRightClick(event, treeId, treeNode) &#123;
	console.log(treeNode);
