一般匹配
location &#x2F;ref.htm &#123;
    root   html;
    index  index.html index.htm;
&#125;

正则匹配(区分大小写)
location ~ &#x2F;ref &#123;
    root   html;
    index  index.html index.htm;
&#125;

正则匹配(不区分大小写)
location ~* &#x2F;ref &#123;
    root   html;
    index  index.html index.htm;
&#125;

不使用正则匹配
location ^~ &#x2F;ref &#123;
    root   html;
    index  index.html index.htm;
&#125;

